require('dotenv').config();
const mongoose = require('mongoose');
const Professional = require('./models');

const data = {
  professionalName: "Gary Selios",
    base64Image: "",
   nameLink: {
    firstName: "Gary: ",
    url: "https://github.com/garyselios"
  },
  primaryDescription: "Systems administrator with experience in on-premise and cloud infrastructure",
  workDescription1: "Management of Windows Server (2016/2019/2022), Active Directory, DNS, DHCP",
  workDescription2: "Automation with PowerShell and Bash, monitoring with Zabbix, backups with Veeam",
  linkTitleText: "Find me at:",
  linkedInLink: {
    text: "My LinkedIn",
    link: "https://www.linkedin.com/in/gary-selios-bennett-0342b0130/?locale=en_US"
  },
  githubLink: {
    text: "My GitHub",
    link: "https://github.com/garyselios"
  }
};

async function seedDatabase() {
  try {
    await mongoose.connect(process.env.MONGODB_URI);
    console.log('Connected to MongoDB');
    
    await Professional.deleteMany({});
    console.log('Cleared existing data');
    
    await Professional.create(data);
    console.log('Data inserted successfully');
    
    console.log('Done!');
    process.exit(0);
  } catch (error) {
    console.error('Error:', error);
    process.exit(1);
  }
}

seedDatabase();